class Solution:
    def countTime(self, time):
        # brute force over all 24*60 actual times, checking each against the template
        count = 0
        for h in range(24):
            for m in range(60):
                cand = '%02d:%02d' % (h, m)
                ok = True
                for a, b in zip(time, cand):
                    if a != '?' and a != b:
                        ok = False
                        break
                if ok:
                    count += 1
        return count

