class Solution:
    def countTime(self, time):
        def ways(slots, hi):
            c = 0
            for v in range(hi + 1):
                s = '%02d' % v
                if (slots[0] == '?' or slots[0] == s[0]) and (slots[1] == '?' or slots[1] == s[1]):
                    c += 1
            return c
        return ways(time[0:2], 23) * ways(time[3:5], 59)

