var countTime = function(time) {
    function ways(a, b, hi) {
        let c = 0;
        for (let v = 0; v <= hi; v++) {
            const s = String(v).padStart(2, '0');
            if ((a === '?' || a === s[0]) && (b === '?' || b === s[1])) c++;
        }
        return c;
    }
    return ways(time[0], time[1], 23) * ways(time[3], time[4], 59);
};
